import { Buffer } from 'buffer';
import { StamperWithKeyManagement, Algorithm, StamperKeyInfo } from '@phantom/sdk-types';

type IndexedDbStamperConfig = {
    dbName?: string;
    storeName?: string;
    keyName?: string;
    type?: "PKI" | "OIDC";
    idToken?: string;
    salt?: string;
};
/**
 * IndexedDB-based key manager that stores cryptographic keys securely in IndexedDB
 * and performs signing operations without ever exposing private key material.
 *
 * Algorithm selection:
 * - Prefers Ed25519 for maximum security and performance
 * - Automatically falls back to ECDSA P-256 (secp256r1) on browsers that don't support Ed25519
 *   (e.g., older Android WebViews before Chrome 113)
 *
 * Security model:
 * - Generates non-extractable keypairs using Web Crypto API
 * - Stores keys entirely within Web Crypto API secure context
 * - Private keys NEVER exist in JavaScript memory
 * - Provides signing methods without exposing private keys
 * - Maximum security using browser's native cryptographic isolation
 */
declare class IndexedDbStamper implements StamperWithKeyManagement {
    private dbName;
    private storeName;
    private keyName;
    private db;
    private activeKeyPairRecord;
    private pendingKeyPairRecord;
    algorithm: Algorithm;
    type: "PKI" | "OIDC";
    idToken?: string;
    salt?: string;
    constructor(config?: IndexedDbStamperConfig);
    /**
     * Initialize the stamper by opening IndexedDB and retrieving or generating keys.
     * Automatically selects the best supported algorithm.
     */
    init(): Promise<StamperKeyInfo>;
    private getSupportedAlgorithm;
    /**
     * Get the public key information
     */
    getKeyInfo(): StamperKeyInfo | null;
    /**
     * Reset the key pair by generating a new one
     */
    resetKeyPair(): Promise<StamperKeyInfo>;
    /**
     * Create X-Phantom-Stamp header value using stored private key
     * @param params - Parameters object with data and optional type/options
     * @returns Complete X-Phantom-Stamp header value
     */
    stamp(params: {
        data: Buffer;
        type?: "PKI";
        idToken?: never;
        salt?: never;
    } | {
        data: Buffer;
        type: "OIDC";
        idToken: string;
        salt: string;
    }): Promise<string>;
    /**
     * Clear all stored keys
     */
    clear(): Promise<void>;
    private clearStoredKeys;
    private openDB;
    /**
     * Generate a new keypair for rotation without making it active
     */
    rotateKeyPair(): Promise<StamperKeyInfo>;
    /**
     * Switch to the pending keypair, making it active and cleaning up the old one
     */
    commitRotation(authenticatorId: string): Promise<void>;
    /**
     * Discard the pending keypair on rotation failure
     */
    rollbackRotation(): Promise<void>;
    private generateAndStoreNewKeyPair;
    private storeKeyPairRecord;
    private loadActiveKeyPairRecord;
    private loadPendingKeyPairRecord;
    private removeKeyPairRecord;
}

export { IndexedDbStamper, IndexedDbStamperConfig };
